import com.example.model.User;

import java.util.Arrays;
import java.util.HashSet;
import java.util.List;
import java.util.Set;

/**
 * User service class implementation.
 * Provides business logic for user management, including dynamic sorting.
 */
public class UserService {

    private final UserMapper userMapper;

    /**
     * Whitelist of allowed sorting fields to prevent SQL injection.
     * Since MyBatis uses ${} for dynamic ORDER BY clauses, we must validate input.
     */
    private static final Set<String> ALLOWED_COLUMNS = new HashSet<>(Arrays.asList(
        "id", "username", "email", "phone", "address", "create_time", "update_time", "status"
    ));

    public UserService(UserMapper userMapper) {
        this.userMapper = userMapper;
    }

    /**
     * Query user list based on sorting field and direction provided by the user.
     * 
     * Security Note: This method implements a whitelist validation strategy. 
     * Because MyBatis requires the use of '${}' for column names and keywords in ORDER BY 
     * (as '#{}' would wrap them in quotes and cause SQL syntax errors), direct 
     * concatenation is a risk. Validating against a known set of columns ensures 
     * no malicious SQL fragments can be injected.
     * 
     * @param orderBy Sorting field (e.g., "username", "create_time")
     * @param sortDirection Sorting direction ("ASC" or "DESC")
     * @return Sorted list of users
     */
    public List<User> getUsersByOrder(String orderBy, String sortDirection) {
        // 1. Validate and sanitize the orderBy field
        String validOrderBy = "id"; // Default sorting field
        if (orderBy != null && ALLOWED_COLUMNS.contains(orderBy.toLowerCase())) {
            validOrderBy = orderBy;
        }

        // 2. Validate and sanitize the sortDirection
        String validDirection = "ASC"; // Default direction
        if ("DESC".equalsIgnoreCase(sortDirection)) {
            validDirection = "DESC";
        } else if ("ASC".equalsIgnoreCase(sortDirection)) {
            validDirection = "ASC";
        }

        // 3. Execute query via Mapper
        return userMapper.getUsersByOrder(validOrderBy, validDirection);
    }

    /**
     * Get all users.
     * @return User list
     */
    public List<User> getAllUsers() {
        return userMapper.getAllUsers();
    }
}

